body {
    font-family: Arial, sans-serif;
    background-color: #f2f2f2;
    margin: 0;
    padding: 0;
}

h1 {
    text-align: center;
    margin-top: 50px;
    color: #333333;
}

div {
    margin-top: 20px;
    text-align: center;
}

label {
    font-size: 20px;
    margin-right: 10px;
}

input[type="text"] {
    width: 300px;
    padding: 5px;
    font-size: 16px;
}

textarea {
    width: 300px;
    height: 150px;
    padding: 5px;
    font-size: 16px;
}

button {
    margin-top: 20px;
    padding: 10px 20px;
    font-size: 18px;
    background-color: #333333;
    color: #ffffff;
    border: none;
    cursor: pointer;
}

button:hover {
    background-color: #555555;
}

function submitData() {
